INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100210, 38, "すべてのモンスターが一度の行動で受けるダメージの値が「2000000」以上の場合、ダメージの値に応じてダメージ量を減少させる。", "ダメージ減衰", 10021002);
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100210, "boss_def_lower_limit", "バトル開始時、すべてのモンスターの物理防御力を特大アップさせる。この効果は物理防御力ダウンの影響を受けない。", "物理防御力（ダウン不可）アップ", 10021003);
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100210, "boss_magic_def_lower_limit", "バトル開始時、すべてのモンスターの魔法防御力を特大アップさせる。この効果は魔法防御力ダウンの影響を受けない。", "魔法防御力（ダウン不可）アップ", 10021004);
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100210, "boss_tp_down_cut", "バトル開始時、すべてのモンスターがＴＰダウン\n100％カット状態になる。", "ＴＰダウンカット", 10021005);
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100210, 3, "バトル開始時、すべてのキャラのＴＰ上昇を中ダウンさせる。", "ＴＰ上昇ダウン", 10021006);
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100210, 9, "バトル開始時、すべてのキャラのＨＰ吸収を特大ダウンさせる。", "ＨＰ吸収ダウン", 10021007);
